<?php
require_once __DIR__.'/app/layout.php'; require_login();
$rows=db()->query('SELECT * FROM employees ORDER BY active DESC,name')->fetchAll();
page_header('Data Pegawai','employees');?><div class="card"><div class="section-title"><h2>Daftar Pegawai</h2><?php if((current_user()['role']??'')==='admin'):?><a class="btn" href="employee_form.php">Tambah pegawai</a><?php endif;?></div><?php foreach($rows as $r):?><div class="employee-card"><div><h3><?=e($r['name'])?> <?php if(!$r['active']):?><span class="badge danger">Nonaktif</span><?php endif;?></h3><p>NIP <?=e($r['nip']?:'-')?> · Gol <?=e($r['grade']?:'-')?></p><p><?=e($r['position']?:'-')?></p><span class="badge <?=$r['signature_path']?'ok':'warn'?>">TTD <?=$r['signature_path']?'tersedia':'belum ada'?></span></div><div class="actions-inline"><?php if($r['signature_path']):?><img class="signature-thumb" src="<?=e($r['signature_path'])?>" alt="TTD"><?php endif;?><?php if((current_user()['role']??'')==='admin'):?><a class="btn secondary small" href="employee_form.php?id=<?=$r['id']?>">Ubah</a><?php endif;?></div></div><?php endforeach;?></div><?php page_footer();
